import React, { useState, useMemo } from 'react';

export default function ProductFilter({ products }) {
  const categories = useMemo(() => [...new Set(products.map((p) => p.category))], [products]);
  const [cats, setCats] = useState(() => new Set());
  const [maxPrice, setMaxPrice] = useState(500);
  const [sort, setSort] = useState('none');

  const toggleCat = (c) =>
    setCats((s) => {
      const n = new Set(s);
      if (n.has(c)) n.delete(c);
      else n.add(c);
      return n;
    });

  const shown = useMemo(() => {
    let r = products.filter((p) => (cats.size === 0 || cats.has(p.category)) && p.price <= maxPrice);
    if (sort === 'asc') r = [...r].sort((a, b) => a.price - b.price);
    if (sort === 'desc') r = [...r].sort((a, b) => b.price - a.price);
    return r;
  }, [products, cats, maxPrice, sort]);

  return (
    <div style={{ display: 'flex', gap: 20 }}>
      <aside style={{ width: 180 }}>
        <h3 style={{ fontSize: 14 }}>Category</h3>
        {categories.map((c) => (
          <label key={c} style={{ display: 'flex', gap: 6, marginBottom: 4 }}>
            <input type="checkbox" checked={cats.has(c)} onChange={() => toggleCat(c)} />
            {c}
          </label>
        ))}
        <h3 style={{ fontSize: 14, marginTop: 16 }}>Max price: ${maxPrice}</h3>
        <input type="range" min="0" max="500" value={maxPrice} onChange={(e) => setMaxPrice(Number(e.target.value))} style={{ width: '100%' }} />
        <h3 style={{ fontSize: 14, marginTop: 16 }}>Sort</h3>
        <select value={sort} onChange={(e) => setSort(e.target.value)} style={{ width: '100%', padding: 6 }}>
          <option value="none">Default</option>
          <option value="asc">Price ↑</option>
          <option value="desc">Price ↓</option>
        </select>
      </aside>

      <main style={{ flex: 1 }}>
        <p style={{ color: '#666' }}>{shown.length} products</p>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(120px, 1fr))', gap: 12 }}>
          {shown.map((p) => (
            <div key={p.id} style={{ border: '1px solid #e5e7eb', borderRadius: 10, padding: 12 }}>
              <div style={{ height: 60, borderRadius: 6, background: '#eef2ff', marginBottom: 8 }} />
              <div style={{ fontWeight: 600 }}>{p.name}</div>
              <div style={{ color: '#64748b', fontSize: 13 }}>{p.category}</div>
              <div style={{ marginTop: 4 }}>${p.price}</div>
            </div>
          ))}
          {shown.length === 0 && <p style={{ color: '#aaa' }}>No products match.</p>}
        </div>
      </main>
    </div>
  );
}

