import { Component, Input } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface Product { id: number; name: string; category: string; price: number; }

@Component({
  selector: 'app-product-filter',
  template: `
    <div style="display: flex; gap: 20px;">
      <aside style="width: 180px;">
        <h3 style="font-size: 14px; margin: 0 0 6px;">Category</h3>
        <label *ngFor="let c of categories" style="display: flex; gap: 6px; margin-bottom: 4px;">
          <input type="checkbox" [checked]="cats.has(c)" (change)="toggleCat(c)" />
          {{ c }}
        </label>
        <h3 style="font-size: 14px; margin: 16px 0 6px;">Max price: ${{ maxPrice }}</h3>
        <input type="range" min="0" max="500" [value]="maxPrice" (input)="maxPrice = toNum($any($event.target).value)" style="width: 100%;" />
        <h3 style="font-size: 14px; margin: 16px 0 6px;">Sort</h3>
        <select [value]="sort" (change)="sort = $any($event.target).value" style="width: 100%; padding: 6px;">
          <option value="none">Default</option>
          <option value="asc">Price ↑</option>
          <option value="desc">Price ↓</option>
        </select>
      </aside>

      <main style="flex: 1;">
        <p style="color: #666;">{{ shown.length }} products</p>
        <div style="display: grid; grid-template-columns: repeat(auto-fill, minmax(120px, 1fr)); gap: 12px;">
          <div *ngFor="let p of shown" style="border: 1px solid #e5e7eb; border-radius: 10px; padding: 12px;">
            <div style="height: 60px; border-radius: 6px; background: #eef2ff; margin-bottom: 8px;"></div>
            <div style="font-weight: 600;">{{ p.name }}</div>
            <div style="color: #64748b; font-size: 13px;">{{ p.category }}</div>
            <div style="margin-top: 4px;">${{ p.price }}</div>
          </div>
          <p *ngIf="shown.length === 0" style="color: #aaa;">No products match.</p>
        </div>
      </main>
    </div>
  `,
})
export class ProductFilterComponent {
  @Input() products: Product[] = [];
  cats = new Set<string>();
  maxPrice = 500;
  sort = 'none';

  get categories(): string[] {
    return [...new Set(this.products.map((p) => p.category))];
  }

  toNum(v: string): number {
    return Number(v);
  }

  toggleCat(c: string): void {
    if (this.cats.has(c)) {
      this.cats.delete(c);
    } else {
      this.cats.add(c);
    }
  }

  get shown(): Product[] {
    let r = this.products.filter(
      (p) => (this.cats.size === 0 || this.cats.has(p.category)) && p.price <= this.maxPrice
    );
    if (this.sort === 'asc') {
      r = [...r].sort((a, b) => a.price - b.price);
    }
    if (this.sort === 'desc') {
      r = [...r].sort((a, b) => b.price - a.price);
    }
    return r;
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Product Filter Demo</h1>
      <app-product-filter [products]="products"></app-product-filter>
    </div>
  `,
})
export class AppComponent {
  products: Product[] = [
    { id: 1, name: 'Headphones', category: 'Audio', price: 120 },
    { id: 2, name: 'Speaker', category: 'Audio', price: 80 },
    { id: 3, name: 'Keyboard', category: 'Computers', price: 60 },
    { id: 4, name: 'Mouse', category: 'Computers', price: 30 },
    { id: 5, name: 'Monitor', category: 'Computers', price: 220 },
    { id: 6, name: 'Camera', category: 'Photo', price: 450 },
    { id: 7, name: 'Tripod', category: 'Photo', price: 40 },
    { id: 8, name: 'Earbuds', category: 'Audio', price: 95 },
  ];
}

@NgModule({
  declarations: [AppComponent, ProductFilterComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
